using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class BacklogTraining : TrainingContentBase
{
    public BacklogTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Overview",
            Slug = "backlog-overview",
            Summary = "What the backlog is, how it relates to the kanban board, filtering jobs, view modes, and creating new jobs.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","jobs","kanban"]""",
            ContentJson = """{"body":"## Backlog Overview\n\nThe Backlog is your master list of all jobs across every track type. While the Kanban Board gives you a visual, stage-by-stage view of a single track, the Backlog lets you see every job in the system at once — search, filter, sort, and triage work before it hits the board.\n\n### Backlog vs. Kanban Board\n\nThe Kanban Board shows jobs organized into columns by stage within a single track type (e.g., Production, R&D/Tooling, Maintenance). You interact with jobs visually — dragging cards between stages, seeing WIP limits, and tracking flow.\n\nThe Backlog is a flat list of all jobs regardless of track type. It is the place to:\n- **Find any job** by number, title, customer, or assignee\n- **Triage incoming work** — review unassigned or low-priority jobs\n- **Bulk review** — scan across tracks to spot overdue items, unbalanced workloads, or stalled jobs\n- **Create new jobs** that land on the board in their track's first stage\n\nEvery job in the Backlog also appears on its corresponding Kanban Board. Changes made in either place are reflected in both.\n\n### Two View Modes\n\nThe Backlog offers two ways to look at your jobs:\n\n**Table View (default)** — A sortable, filterable list with columns for a job's number, title, stage, priority, who it's assigned to, customer, and due date. Click a column heading to sort by it. Use a column's filter icon to narrow by that column. Click any row to open the full job.\n\n**Card View** — A grid of job cards showing each job's number, title, stage (as a colored label), priority, who it's assigned to, customer, and due date. Cards with an active hold show an 'On Hold' badge, and overdue cards are highlighted. Click any card to open the full job.\n\nSwitch between the two views using the view buttons in the page header. Your choice is remembered and restored on your next visit.\n\n### Filtering\n\nFour filters in the page header narrow down the list:\n\n- **Search** — free-text search across job number and title. Results update as you type.\n- **Track Type** — filter to a specific track (Production, R&D/Tooling, etc.). Shows only jobs whose current stage belongs to that track.\n- **Priority** — filter by Low, Normal, High, or Urgent.\n- **Assignee** — filter to jobs assigned to a specific team member.\n\nAll filters work together (AND logic). The filtered count is reflected in both table and card views.\n\n### Creating Jobs\n\nClick the 'Create Job' button (with the + icon) in the page header to open the job creation dialog. You will enter:\n\n- **Title** (required, max 200 characters)\n- **Description** (optional, multi-line)\n- **Track Type** (required) — determines which board and initial stage the job enters\n- **Customer** (optional) — links the job to a customer record\n- **Assignee** (optional) — assigns a team member. If the selected user has an incomplete profile, a warning is shown.\n- **Priority** (defaults to Normal) — Low, Normal, High, or Urgent\n- **Due Date** (optional) — displayed in red when overdue\n\nThe new job is placed in the first stage of the selected track type and appears on both the Backlog and the Kanban Board immediately.\n\n### Job Detail\n\nClicking any row or card opens the full job. The page link updates to point at that job, so you can share it or bookmark it. From the job's detail you can edit it, view subtasks, files, the activity log, and more.\n\n### Editing an Existing Job\n\nThere is no Edit button directly on the backlog row or card. To edit a job, open it first: click the row or card to open the job, then use its **Edit** action. The job re-opens in the same panel you use to create jobs — but now in **edit mode** (the title reads 'Edit Job'). When you save, the list reloads and your changes appear.\n\nTwo things behave differently in edit mode versus create mode:\n- **Track Type is immutable.** The Track Type field is hidden entirely when editing. A job's track type is fixed at creation because it determines which Kanban board the job lives on — moving a job to a different board would orphan its stage history, so the system does not allow it. If a job is on the wrong track, archive it and create a replacement on the correct track.\n- **The Sales Order line association is create-only.** The field that links a new job to a sales-order line appears only in create mode and is hidden when editing.\n\nEverything else — Title, Description, Customer, Assignee, Priority, and Due Date — is editable. The save button reads 'Save Changes' instead of 'Create Job'.\n\n### Admin: Archived Jobs\n\nJobs are never hard-deleted — when a job is removed from a board it is **archived** (soft-deleted), so it disappears from the active backlog and board but is fully recoverable. Administrators get a recovery path right on the backlog.\n\n**Show Archived / Show Active toggle.** Admins see an extra icon button in the page header (an inventory-box icon). Click it to switch the list from active jobs to archived jobs; the tooltip and icon flip between 'Show archived jobs' and 'Show active jobs'. The list reloads to show a genuinely separate set of jobs — the archived ones — not just a filtered-down view of the active list. Non-admins never see this toggle and cannot reach the archived view.\n\n**Row-level Unarchive.** In the archived view, the table gains an **Actions** column with an Unarchive button on each row. Clicking it asks you to confirm ('Restore this job?'), then restores that single job to the active list. Because the job is now active again, it drops out of the archived view on the next reload and reappears on its Kanban board.\n\n**Bulk Unarchive.** The archived table also becomes selectable: a checkbox appears on each row. Select one or more archived jobs and a bulk action bar slides up from the bottom showing the selected count and an **Unarchive selected** button. Confirm the prompt ('Restore selected jobs?') and all selected jobs are restored in one operation. A success message reports how many were restored. Use the X on the bulk bar to clear the selection without acting.\n\nBoth the toggle and the unarchive actions are Admin-only in the UI, and the server independently enforces the Admin role — restoring work that someone deliberately archived is high-impact, so it is deliberately gated.\n\n### Row Styling (Table View)\n\n- **Overdue rows** get a faint red tint, showing the due date has passed.\n- **Selected row** is highlighted to show which job you currently have open.\n- **Stage color tint** — each row carries a faint background tint in its stage's color, so you can tell a job's stage at a glance.\n\n### Priority Colors\n\nPriority is shown as a colored dot next to the priority name:\n- **Low** — slate gray\n- **Normal** — teal\n- **High** — amber\n- **Urgent** — red","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog — Guided Tour",
            Slug = "backlog-walkthrough",
            Summary = "A guided tour of the backlog page: search, filters, table view, card view toggle, creating jobs, and opening job details.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","walkthrough"]""",
            ContentJson = """{"appRoute":"/backlog","startButtonLabel":"Tour Backlog","steps":[{"element":".page-header app-input","popover":{"title":"Search Jobs","description":"Type here to search by job number or title. The list narrows as you type. Search works whether you are viewing the table or the cards.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(1)","popover":{"title":"Track Type Filter","description":"Narrow the list to one track, such as Production, R&D/Tooling, or Maintenance. Pick 'All Tracks' to see every job again.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(2)","popover":{"title":"Priority Filter","description":"Show only jobs at one priority: Low, Normal, High, or Urgent. Pick 'All Priorities' to see them all.","side":"bottom"}},{"element":".page-header app-select:nth-of-type(3)","popover":{"title":"Assignee Filter","description":"Show only jobs assigned to one person. Pick 'All Assignees' to remove the filter.","side":"bottom"}},{"element":".view-toggle","popover":{"title":"Switch Views","description":"Switch between the table and the card grid. The table is a sortable, filterable list. The cards show each job with its stage color, priority, and who it is assigned to. Your choice is remembered for next time.","side":"bottom"}},{"element":".new-job-btn","popover":{"title":"Create Job","description":"Open the panel to add a job. You give it a title (required) and pick a track (required, which decides its board). You can also add a description, customer, assignee, priority, and due date. The new job starts in the first stage of that track.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Jobs Table","description":"This is the list of all matching jobs, showing each one's number, title, stage, priority, who it is assigned to, customer, and due date. Click a column heading to sort by it. Use the filter icon on a column to narrow by that column. Click any row to open the full job.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Field Reference",
            Slug = "backlog-field-reference",
            Summary = "Complete reference for every field, column, filter, button, validation rule, row style, and view mode in the Backlog.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","reference"]""",
            ContentJson = """{"title":"Backlog Field Reference","groups":[{"heading":"Page Header Filters","items":[{"label":"Search","value":"A text box. Narrows the list to jobs whose title or number contains what you type. Ignores capitalization and matches anywhere in the text. The list updates as you type."},{"label":"Track Type","value":"A menu you pick from. Choose 'All Tracks' (the default) to see every job, or pick one track such as Production, R&D/Tooling, or Maintenance to see only jobs currently in a stage of that track."},{"label":"Priority","value":"A menu you pick from. Choose 'All Priorities' (the default), Low, Normal, High, or Urgent to see only jobs at that priority."},{"label":"Assignee","value":"A menu you pick from. Choose 'All Assignees' (the default) or a person's name to see only the jobs assigned to them."}]},{"heading":"Switch Views","items":[{"label":"Table view button","value":"Shows the jobs as a sortable, filterable list. This is the view you start in."},{"label":"Card view button","value":"Shows the jobs as a grid of cards."},{"label":"Your view is remembered","value":"Whichever view you last used is restored the next time you visit. A link that specifies a view opens in that view instead."}]},{"heading":"Job Create/Edit Panel Fields","items":[{"label":"Title (required)","value":"A text box, up to 200 characters. This name appears on the board cards, the backlog list, and the job's detail."},{"label":"Description","value":"A multi-line box for extra notes about the job. Optional."},{"label":"Track Type (when creating only)","value":"A required menu you pick from, offering the tracks set up for your company. It decides which board and starting stage the job enters. It is hidden when editing, because a job's track cannot change after it is created. To move a job to another track, archive it and create a replacement on the correct track."},{"label":"Customer","value":"An optional menu you pick from, listing your customers plus a 'None' choice. Links the job to a customer."},{"label":"Assignee","value":"An optional menu you pick from, listing your team plus a 'None' choice. If the person you pick has not finished setting up their profile, a warning appears under the field."},{"label":"Priority","value":"A menu you pick from: Low, Normal, High, or Urgent. Defaults to Normal. Sets the priority color shown in the list and on the cards."},{"label":"Due Date","value":"An optional date picker. If the date has passed, the job is flagged overdue (red in the list, highlighted card in the grid)."},{"label":"Save button","value":"Stays disabled while the form is incomplete or a save is in progress. When something is missing, a red warning triangle with a count sits to its left; click it to see what still needs fixing (such as 'Title is required')."},{"label":"Cancel button","value":"Closes the panel without saving. If you made changes, it asks you to confirm first."}]},{"heading":"List Columns","items":[{"label":"Job Number","value":"The job's automatic number, such as J-1001. You can sort by it and search it."},{"label":"Title","value":"The job's name. You can sort by it and search it."},{"label":"Stage","value":"The job's current stage, shown as a colored label in the stage's color. You can sort and filter by it."},{"label":"Priority","value":"The job's priority, shown as a colored dot next to its name. You can sort and filter by it."},{"label":"Assignee","value":"Who the job is assigned to, shown as their initials. A dash means no one is assigned. You can filter by person."},{"label":"Customer Name","value":"The linked customer, or a dash when there is none. You can sort and filter by it."},{"label":"Due Date","value":"The due date, shown as MM/dd/yyyy. You can sort and filter by it. Overdue dates appear in red."}]},{"heading":"Row Styling (List View)","items":[{"label":"Overdue rows","value":"A row gets a faint red tint when its due date has passed."},{"label":"Selected row","value":"The row is highlighted while you have that job open."},{"label":"Stage color tint","value":"Each row carries a faint background tint in its stage's color, so you can tell a job's stage at a glance."}]},{"heading":"Card View Elements","items":[{"label":"Job Number","value":"Shown at the top of the card."},{"label":"On Hold badge","value":"A warning-colored label at the top of the card, shown when the job has one or more active holds."},{"label":"Title","value":"The job's name, in the body of the card."},{"label":"Stage label","value":"A colored label in the stage's color showing the job's current stage."},{"label":"Priority dot and name","value":"A colored dot next to the priority name. Note: card colors do not always match the list. Only Low and High show a distinct color here, and even High is a slightly different shade; Normal and Urgent fall back to gray. Treat the list colors as the reliable ones — see the Advanced Reference."},{"label":"Assignee","value":"Shows who the job is assigned to as their initials. Hidden when no one is assigned."},{"label":"Customer","value":"Shown below the card details with a business icon, only when a customer is linked."},{"label":"Due Date","value":"Shown at the bottom of the card with a calendar icon. Turns red when overdue, and reads 'No date' when none is set."},{"label":"Overdue card","value":"The whole card is highlighted when the job is overdue."},{"label":"Selected card","value":"The card is highlighted while you have that job open."}]},{"heading":"Buttons and Actions","items":[{"label":"Create Job (page header)","value":"A button with a plus icon that opens the panel to add a new job."},{"label":"Click a row","value":"Opens that job's full detail, and highlights the row while it is open. The link updates so you can share or bookmark it."},{"label":"Click a card","value":"Opens that job's full detail, and highlights the card while it is open. The link updates so you can share or bookmark it."},{"label":"Opening a shared job link","value":"If you open a link that points at a specific job, that job's detail opens on its own when the page loads. This is what makes shared links, bookmarks, and the browser's back and forward buttons work."},{"label":"Editing a job","value":"There is no Edit button on the row or card. Open the job first, then use its Edit action. It reopens in the same panel used to create jobs, now in edit mode (titled 'Edit Job' with a 'Save Changes' button). In edit mode the Track Type field and the sales-order line link are hidden; title, description, customer, assignee, priority, and due date can all still be changed."}]},{"heading":"Archived Jobs View (Admin only)","items":[{"label":"Show Archived / Show Active toggle","value":"An extra button in the page header, shown only to Admins. Click it to switch the list between active and archived jobs; the icon and tooltip flip to match. Each view is loaded fresh from the server, not filtered on screen. Switching also clears any current selection."},{"label":"Unarchive (single row)","value":"In the archived view, each row gains an Unarchive button. Click it and confirm 'Restore this job?' to bring that one job back. It leaves the archived view and returns to its board. Clicking it does not open the job's detail."},{"label":"Selecting rows (archived view)","value":"In the archived view, a checkbox appears on each row so you can select several jobs at once. The selection clears when you switch views or finish a bulk action."},{"label":"Bulk action bar","value":"Appears at the bottom once you select archived jobs. It shows how many are selected, an 'Unarchive selected' button, and an X to clear the selection. After you confirm 'Restore selected jobs?', all of them are restored and a message reports how many."},{"label":"Admin only","value":"The toggle, the Unarchive actions, row selection, and the bulk bar are all limited to Admins, both on screen and on the server — so restoring work someone deliberately archived stays protected."}]},{"heading":"Data Loading","items":[{"label":"When the page opens","value":"The jobs, tracks, and people all load together, with a full-page 'Loading backlog...' overlay while they do."},{"label":"After you save","value":"When you create or edit a job, the panel closes and the list reloads so your changes show up."},{"label":"If loading fails","value":"If the page can't load, it shows an error icon and message instead of the list or cards."}]},{"heading":"Priority Colors","items":[{"label":"Low","value":"Slate gray"},{"label":"Normal","value":"Teal"},{"label":"High","value":"Amber"},{"label":"Urgent","value":"Red"}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog Knowledge Check",
            Slug = "backlog-quiz",
            Summary = "Test your knowledge of the Backlog module: filters, view modes, job creation, table columns, and card elements.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 7,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"bl1","text":"What is the primary purpose of the Backlog page compared to the Kanban Board?","options":[{"id":"a","text":"The Backlog replaces the Kanban Board for teams that prefer list views"},{"id":"b","text":"The Backlog shows all jobs across every track type in a flat list for searching, filtering, and triaging work","isCorrect":true},{"id":"c","text":"The Backlog only shows jobs that haven't been assigned to a track yet"},{"id":"d","text":"The Backlog is a historical archive of completed jobs"}],"explanation":"The Backlog is a master list of all jobs across every track type. While the Kanban Board shows one track at a time organized by stage columns, the Backlog lets you see, search, and filter all jobs regardless of which track they belong to."},{"id":"bl2","text":"You want to find all urgent jobs assigned to a specific team member. What filters do you set?","options":[{"id":"a","text":"Set the Search field to the team member's name and the Priority filter to Urgent"},{"id":"b","text":"Set the Assignee filter to the team member and the Priority filter to Urgent","isCorrect":true},{"id":"c","text":"Set the Track Type filter and then sort the Priority column descending"},{"id":"d","text":"Use the Search field to type 'urgent' and scan the results visually"}],"explanation":"The Backlog has dedicated Assignee and Priority filters in the page header. Set Assignee to the team member's name and Priority to Urgent. These filters work together with AND logic, showing only jobs matching both criteria."},{"id":"bl3","text":"What happens when you switch from Table view to Card view?","options":[{"id":"a","text":"The link updates to note the card view, and your choice is remembered for next time","isCorrect":true},{"id":"b","text":"Only the display changes — nothing is remembered"},{"id":"c","text":"You are taken to a completely different page"},{"id":"d","text":"The card view opens in a new browser tab"}],"explanation":"When you switch to cards, the page link updates to note it, and your choice is remembered so the backlog opens the same way next time. The table is the default and doesn't change the link. Your choice sticks across sessions."},{"id":"bl4","text":"In the panel for creating a job, which fields are required?","options":[{"id":"a","text":"Title, Description, and Track Type"},{"id":"b","text":"Title and Track Type","isCorrect":true},{"id":"c","text":"Title, Track Type, Priority, and Customer"},{"id":"d","text":"Only Title is required — Track Type is picked for you"}],"explanation":"Creating a job requires a Title (up to 200 characters) and a Track Type. Everything else — Description, Customer, Assignee, Priority, and Due Date — is optional. Priority starts at Normal unless you change it."},{"id":"bl5","text":"You want to add a brand-new job to the Backlog. What do you do?","options":[{"id":"a","text":"Click the Create Job button in the page header, then fill in the details — at least a title and a track — in the panel that opens and save","isCorrect":true},{"id":"b","text":"Double-click an empty area of the jobs list to start a new row and type the job in place"},{"id":"c","text":"Open any existing job, edit its title and track, and save it as a copy"},{"id":"d","text":"Switch to card view first — new jobs can only be created from the card grid"}],"explanation":"Click the Create Job button (the one with the plus icon) in the page header. A panel opens where you enter the job's details: a Title and Track Type are required, and you can also set a Description, Customer, Assignee, Priority, and Due Date. When you save, the new job lands in the first stage of the track you picked and appears on both the Backlog and its Kanban board. There's no in-place row editing, no save-as-copy, and creating a job works the same in either view."},{"id":"bl6","text":"A job row in the list has a red background tint. What does this indicate?","options":[{"id":"a","text":"The job has a critical priority level"},{"id":"b","text":"The job has an error and needs attention"},{"id":"c","text":"The job's due date has passed — it is overdue","isCorrect":true},{"id":"d","text":"The job is currently on hold"}],"explanation":"A row turns faintly red when the job's due date has passed. This is separate from the faint stage-color tint every row carries, which is always present."},{"id":"bl7","text":"Every row in the list carries a faint background tint. What does that tint tell you?","options":[{"id":"a","text":"It matches the job's priority color"},{"id":"b","text":"It matches the job's current stage color","isCorrect":true},{"id":"c","text":"It marks the left border of each row"},{"id":"d","text":"It highlights the row when you hover over it"}],"explanation":"Each row carries a faint background tint in its current stage's color. This lets you tell a job's stage at a glance, even without reading the Stage column."},{"id":"bl8","text":"When does the Track Type field appear in the job panel?","options":[{"id":"a","text":"It always appears, whether you're creating or editing"},{"id":"b","text":"Only when creating — the track can't change after a job is created","isCorrect":true},{"id":"c","text":"Only when editing — creating a job picks a default track for you"},{"id":"d","text":"It appears as a read-only field when editing"}],"explanation":"The Track Type field only shows up when you're creating a job. Once a job exists, its track is fixed and decides which board it belongs to, so the field is hidden entirely when you edit."},{"id":"bl9","text":"How can you share a direct link to one job's detail?","options":[{"id":"a","text":"You can't — links only ever open the backlog list"},{"id":"b","text":"Opening a job updates the page link so it points at that job, and the link reopens its detail on its own","isCorrect":true},{"id":"c","text":"Deep linking is not supported — you must click a row to see details"},{"id":"d","text":"You copy the job number and paste it into a search box"}],"explanation":"When you open a job, the page link updates to point at it. Sharing or bookmarking that link reopens the job's detail on its own when the page loads, and it makes the browser's back and forward buttons work."},{"id":"bl10","text":"You switched to card view and then close the Backlog. When you come back to it later, which view will you see?","options":[{"id":"a","text":"Card view — the Backlog remembers whichever view you last used and restores it","isCorrect":true},{"id":"b","text":"Table view — the Backlog always resets to the table each time you open it"},{"id":"c","text":"Whichever view a co-worker used most recently, since the setting is shared"},{"id":"d","text":"It asks you to pick a view again every time the page loads"}],"explanation":"Your view choice is remembered and restored the next time you visit, so if you left the Backlog in card view you'll return to card view. The preference is yours alone, not shared with co-workers. The one exception is a link that specifies a view — opening that link shows the view it names regardless of your saved choice."},{"id":"bl11","text":"In card view, what makes the 'On Hold' badge appear on a job card?","options":[{"id":"a","text":"The job's priority is set to Urgent"},{"id":"b","text":"The job has been in the same stage for more than 7 days"},{"id":"c","text":"The job has one or more active holds","isCorrect":true},{"id":"d","text":"The job's assignee has not logged in recently"}],"explanation":"The 'On Hold' badge, a warning-colored label at the top of the card, appears when the job has one or more active holds. Holds are placed from the job's detail and mean the job is blocked or paused."},{"id":"bl12","text":"What color represents a 'High' priority job's dot in the backlog list?","options":[{"id":"a","text":"Red"},{"id":"b","text":"Teal"},{"id":"c","text":"Amber","isCorrect":true},{"id":"d","text":"Slate gray"}],"explanation":"In the list, priority colors are: Low is slate gray, Normal is teal, High is amber, and Urgent is red. These are the reliable colors. The card view can show different colors — see the Advanced Reference for that gap."},{"id":"bl13","text":"How do you find out what's missing when the Save button is disabled in the job panel?","options":[{"id":"a","text":"Nothing — the button is grayed out with no other feedback"},{"id":"b","text":"A tooltip says 'Please fill in all required fields'"},{"id":"c","text":"A red warning triangle with a count sits to the left of Save; click it to see the list of what needs fixing (such as 'Title is required')","isCorrect":true},{"id":"d","text":"The empty fields flash red to draw attention"}],"explanation":"When the form isn't ready, a red warning triangle with a count sits to the left of the still-disabled Save button. Click it to see exactly what needs fixing, such as 'Title is required' or 'Track Type is required'. This is the standard Forge pattern — you click to reveal the list rather than hover for a tooltip."},{"id":"bl14","text":"How does the Track Type filter decide which jobs to show?","options":[{"id":"a","text":"By a track label stored directly on each job"},{"id":"b","text":"By whether the job's current stage belongs to the selected track","isCorrect":true},{"id":"c","text":"It groups the rows by track and collapses the ones you didn't pick"},{"id":"d","text":"It takes you to the Kanban Board for that track"}],"explanation":"The filter shows a job when its current stage belongs to the selected track. So a job appears based on the stage it's sitting in, not on a track label attached to the job itself."},{"id":"bl15","text":"What does the Due Date on a job mean, and how does the Backlog use it?","options":[{"id":"a","text":"It's the job's target completion date. The Backlog uses it to order work and flags jobs as overdue once the date has passed","isCorrect":true},{"id":"b","text":"It's the date the job was created, and it can't be changed afterward"},{"id":"c","text":"It's the last day you're allowed to edit the job before it locks"},{"id":"d","text":"It's required on every job, and the job can't be saved without one"}],"explanation":"The Due Date is the job's target completion date. It's optional — a job can have no due date at all. Once the date has passed, the job is flagged overdue: its row turns faintly red in the list and its card is highlighted in the grid, so you can spot late or approaching work at a glance and prioritize accordingly. It is not the creation date, it doesn't lock the job, and it isn't required."},{"id":"bl16","text":"You are an admin and want to review jobs that were archived off the board. How do you get to them from the Backlog?","options":[{"id":"a","text":"Set the Track Type filter to 'Archived'"},{"id":"b","text":"Click the archived-jobs button in the page header to switch from active to archived jobs","isCorrect":true},{"id":"c","text":"Type 'archived' into the Search field"},{"id":"d","text":"Archived jobs cannot be viewed — they are permanently deleted"}],"explanation":"Admins get an extra button in the page header that switches the list between active and archived jobs. Each view is loaded fresh from the server, not filtered on screen. Non-admins never see this button. Archived jobs are never truly deleted, so they can always be restored."},{"id":"bl17","text":"In the admin archived view, how do you restore several jobs to the active list at once?","options":[{"id":"a","text":"Check the boxes on the archived rows, then click 'Unarchive selected' in the bulk action bar and confirm","isCorrect":true},{"id":"b","text":"There is no bulk option — you must unarchive each job one row at a time"},{"id":"c","text":"Drag the selected jobs back onto the Kanban board"},{"id":"d","text":"Change each job's status to 'Active' in the create panel"}],"explanation":"In the archived view a checkbox appears on each row. Check one or more jobs and a bulk action bar rises at the bottom with the count and an 'Unarchive selected' button. After you confirm 'Restore selected jobs?', all of them are restored at once and a message reports how many. There's also a single Unarchive button per row for the one-at-a-time case."},{"id":"bl18","text":"You open a job and need to change its track from Production to Maintenance. What does the app let you do?","options":[{"id":"a","text":"Open the job, click Edit, and pick a new track from the menu"},{"id":"b","text":"Nothing — the track can't change; the Track field is hidden when editing, so you archive the job and create a replacement on the correct track","isCorrect":true},{"id":"c","text":"Drag the job to the Maintenance board, which reassigns its track"},{"id":"d","text":"The track changes on its own based on the assignee's team"}],"explanation":"To edit a job you open it, then use its Edit action, which reopens it in edit mode. In edit mode the Track field is hidden entirely — a job's track is fixed when it's created because it decides which board the job lives on. To move a job to a different track, archive it and create a replacement on the correct track."}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Backlog — Advanced Reference",
            Slug = "backlog-reference",
            Summary = "Edge-case and power-user notes: assignee profile gating, view-mode persistence, the card-vs-table priority palette gap, the 200-job fetch cap, and empty/error states.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/backlog"]""",
            Tags = """["backlog","reference","advanced"]""",
            ContentJson = """{"body":"## When a teammate's profile isn't ready\n\nWhen you assign a job, the Assignee list shows everyone on your team — but a name can appear with a warning mark and a **(incomplete profile)** note next to it. That means the person hasn't finished their new-hire setup yet: the items that have to be done before someone can take on work are their **W-4**, their **I-9**, their **state tax withholding** (already handled in states with no income tax), and an **emergency contact**. Other setup steps — home address, direct deposit, handbook sign-off — don't hold up job assignment.\n\nThe warning is only a heads-up. You can still assign the job to that person and save; nothing stops you. Use your judgment: if you're staffing work that starts today, it's usually fine, but if the person is brand-new and still finishing paperwork, you may want to hold the assignment until they're set up.\n\n## Card view, table view, and which one you land on\n\nYou can work the backlog as a **table** (the sortable, filterable list) or as a grid of **cards**. Pick whichever fits the task: the table is best for sorting a lot of jobs by due date or priority and scanning columns; the cards are best for a quick visual triage where stage color and the on-hold badge jump out.\n\nWhichever view you leave the backlog in is the one you'll come back to next time — the backlog remembers your choice, and it's yours alone, not shared with co-workers. The one exception is a link someone sends you that already names a view: opening that link shows the view it names, no matter what you last used. So if a co-worker shares a card-view link, you'll open in cards even if you normally use the table; switch back once and the backlog goes back to remembering your preference.\n\n## Priority colors: trust the table, not the card dot\n\nPriority shows as a small colored dot. In the **table** the colors are reliable and consistent: **Low** is slate gray, **Normal** is teal, **High** is amber, and **Urgent** is red. Use these to scan the list for what needs attention first.\n\nOn a **card**, the priority dot is not dependable — only Low and High show a distinct color, and even High is a slightly different shade, while Normal and Urgent fall back to a plain gray dot. So the same job can look one way in the table and another on its card. The fix is simple: on a card, **read the priority word** (Low / Normal / High / Urgent) next to the dot rather than judging by the dot's color. When you're triaging by priority, do it in the table.\n\n## Very large backlogs\n\nThe backlog shows a large but capped batch of jobs at once — roughly the first couple hundred active (or archived) jobs. On most shops that's the whole list. On a very busy install it can mean some jobs sit past the end of the list and don't appear in the flat view.\n\nIf your backlog is that big, don't rely on the full list to show everything. Narrow it first with the **Track Type** and **Assignee** filters, or work a single track from its **Kanban board** instead, where jobs are split across stage columns. The search box and the column sorting always work over what's currently loaded, so filtering down to your area is the reliable way to make sure you're seeing every job you care about.\n\n## When the list is empty or won't load\n\nTwo everyday situations look different on screen:\n\n- **No jobs match** — you'll see a short \"No jobs match your filters\" message with a hint to adjust your search or filters. This isn't an error — it usually just means your filters are too tight. Clear a filter or the search box to widen the list. (Remember: new jobs are added from the Board page or the Create Job button here.)\n- **The backlog can't load** — if the page itself fails to load, you'll get an error message in place of the list instead of the filters and jobs. This is a connection or system problem, not something wrong with your filters. Refresh the page; if it keeps happening, let your admin know.\n\nWhile the backlog is loading, you'll see a brief \"Loading backlog...\" indicator; that's normal and clears on its own once your jobs come in.","sections":[]}"""
        });

        Log.Information("Seeded Backlog training modules");
    }
}
